#!/usr/bin/env node
/**
 * sync-hadar-corpus.mjs
 *
 * Reads HADAR_RAW_QUOTES.md (the master verbatim quote bank in the transcripts
 * repo) and emits lib/prompts/hadar-corpus-quotes.ts — an auto-generated
 * TypeScript file that exposes verbatim Hadar quotes per signature move.
 *
 * The engine (shoot-day-engine.ts) imports INJECTED_QUOTES from that file and
 * appends it to HADAR_SIGNATURE_MOVES. So whenever a new quote is added to
 * HADAR_RAW_QUOTES.md, running this script updates the engine automatically.
 *
 * USAGE:
 *   node scripts/sync-hadar-corpus.mjs
 *   npm run sync-corpus  (once added to package.json)
 *
 * PARSING RULES:
 *   - Two accepted section-heading patterns for moves 1-15:
 *       a) `## N. ...` where N in 9..15  (legacy — archetype moves)
 *       b) `## Move #N — ...` where N in 1..8  (bootstrap 2026-07-10 — core moves)
 *   - Sections 1-8 as `## 1.`-`## 8.` are RESERVED for structural notes (Setup /
 *     Reformulation / etc.) and are NOT scanned; core moves 1-8 live under the
 *     `## Move #N —` pattern so they don't collide.
 *   - Each section's quotes live in a Markdown table. The first data row (after
 *     header + separator) begins with `| N.M | "quote" | source | type |`.
 *
 * OUTPUT: /Users/work/hadar-danan/lib/prompts/hadar-corpus-quotes.ts
 */
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname   = path.dirname(fileURLToPath(import.meta.url));
const REPO_ROOT   = path.resolve(__dirname, "..");
const RAW_QUOTES  = "/Users/work/hadar-transcripts/HADAR_RAW_QUOTES.md";
const OUTPUT_FILE = path.join(REPO_ROOT, "lib/prompts/hadar-corpus-quotes.ts");

const MOVE_NAMES = {
  1:  "External→Internal Translation",
  2:  "Service Reframe",
  3:  "אני אקביל לך Parable-Building",
  4:  "Tangible Metaphor Anchor",
  5:  "Sold-Inversion",
  6:  "Self-as-Example",
  7:  "Projective Embodiment",
  8:  "Anti-Flattery",
  9:  "Sensory-to-Business Translation",
  10: "Process-as-Proof",
  11: "Receptive Embodiment",
  12: "Specificity-as-Service",
  13: "Silent Authority Positioning",
  14: "Category-Rename / Reclaim",
  15: "Diagnostic-Framework Reveal",
};

const MAX_QUOTES_PER_MOVE = 5;  // Cap injection size to avoid prompt bloat.

/**
 * Parse HADAR_RAW_QUOTES.md and return a map: moveNumber -> array of quote objects.
 */
function parseQuotes(mdContent) {
  const lines = mdContent.split("\n");
  const byMove = {};

  let currentMove = null;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    // Detect a move section header. Two accepted patterns:
    //   a) `## N. ...`         → move N (only 9-15; 1-8 as `## N.` are structural)
    //   b) `## Move #N — ...`  → move N (only 1-8; 9-15 use pattern (a))
    const legacyMatch = line.match(/^## (\d+)\.\s/);
    const coreMatch   = line.match(/^## Move #(\d+)\b/);
    if (legacyMatch || coreMatch) {
      const n = parseInt((legacyMatch || coreMatch)[1], 10);
      const legalRange = legacyMatch ? (n >= 9 && n <= 15) : (n >= 1 && n <= 8);
      if (legalRange) {
        currentMove = n;
        byMove[currentMove] = byMove[currentMove] || [];
      } else {
        currentMove = null;
      }
      continue;
    }

    // If a fractional heading like ## 7.05 or ## 7.1 shows up, reset current move
    // to avoid picking up their table rows.
    if (/^## \d+\.\d+\./.test(line)) {
      currentMove = null;
      continue;
    }

    if (currentMove === null) continue;

    // Table row: | N.M | "quote" | source | type |
    // Only match rows where the first cell is `<currentMove>.<subnum>`.
    const rowRegex = new RegExp(`^\\|\\s*${currentMove}\\.\\d+\\s*\\|`);
    if (!rowRegex.test(line)) continue;

    const cells = line.split("|").map((c) => c.trim()).filter((c) => c.length > 0);
    // Expected shape: [N.M, quote, source, type]
    if (cells.length < 3) continue;

    const rawQuote = cells[1];
    const source   = cells[2] || "general";
    const type     = cells[3] || "";

    // Strip markdown bold from quote (**text**), keep the inner text.
    let cleaned = rawQuote.replace(/\*\*(.+?)\*\*/g, "$1").trim();

    // If wrapped in matched straight quotes, extract inner. Handles the common
    // Hebrew markdown pattern `"..."` and also `"..." (annotation)`.
    const wrapped = cleaned.match(/^"([^"]+)"(.*)$/);
    let quote;
    if (wrapped) {
      const inner      = wrapped[1].trim();
      const annotation = wrapped[2].trim();
      quote = annotation ? `${inner} ${annotation}` : inner;
    } else {
      // Fallback: just strip a single leading and trailing `"` if any.
      quote = cleaned.replace(/^"/, "").replace(/"$/, "").trim();
    }

    if (!quote) continue;

    byMove[currentMove].push({ quote, source, type });
  }

  return byMove;
}

/**
 * Emit the generated TypeScript file.
 */
function emit(byMove) {
  const now = new Date().toISOString();

  const header = `/**
 * Auto-generated by scripts/sync-hadar-corpus.mjs — DO NOT EDIT BY HAND.
 * Source of truth: /Users/work/hadar-transcripts/HADAR_RAW_QUOTES.md
 * Generated at: ${now}
 *
 * To update: edit HADAR_RAW_QUOTES.md then run \`npm run sync-corpus\`.
 */

export interface CorpusQuote {
  quote:  string;   // verbatim, Hebrew, no markdown
  source: string;   // C-number or corpus tag (matched against APPROVED_QUOTE_SOURCES)
  type:   string;   // short label of the quote's role
}

export const CORPUS_QUOTES_BY_MOVE: Record<number, CorpusQuote[]> = ${
    JSON.stringify(byMove, null, 2)
  };

`;

  // Build the injection block. THE FRAME MATTERS.
  // Old framing ("verbatim examples, imitate style") caused the model to leak
  // exact phrases from the corpus into customer output. Alon flagged this as
  // an IP-leak vector on 2026-07-10: (a) competitors could reverse-engineer
  // Hadar's playbook from a paying customer's public reel, (b) two customers
  // in the same archetype would get near-identical scripts, breaking the
  // "בהתאמה אישית" promise.
  // New framing: quotes are PATTERN SAMPLES to reverse-engineer, not text to
  // reuse. The model must extract the underlying rhetorical mechanism and
  // regenerate in the customer's domain, in the customer's voice.
  const injectionBlockLines = [
    "בלוק לימוד פנימי — לא לפלט. אלה תבניות מהקול של הדר, לא ציטוטים לשימוש.",
    "",
    "הכלל הברזל: אסור להשתמש באף אחד מהמשפטים למטה verbatim בפלט של הלקוח/ה. אסור להשתמש בחמש מילים רצופות מכל משפט למטה. הפלט הוא של הלקוח/ה — בעולם שלו/ה, בשפה שלו/ה, עם הדוגמאות שלו/ה.",
    "",
    "מה כן לעשות: לקרוא כל משפט, לחלץ את המנגנון הרטורי (המבנה הקצבי, מהלך המחשבה, סוג המטפורה, נקודת ההיפוך). לזרוק את המילים. לכתוב מחדש מהיסוד עם החומר של הלקוח/ה. אם אני מזהה שהוצאת משפט של הדר עם שמות הוחלפו — פסלתי את הפלט.",
    "",
    "הדוגמאות פר מהלך:",
    "",
  ];

  const orderedMoves = Object.keys(byMove)
    .map((k) => parseInt(k, 10))
    .sort((a, b) => a - b);

  for (const n of orderedMoves) {
    const moveName = MOVE_NAMES[n] || `Move ${n}`;
    const quotes   = byMove[n].slice(0, MAX_QUOTES_PER_MOVE);
    if (quotes.length === 0) continue;

    injectionBlockLines.push(`מהלך #${n} — ${moveName}:`);
    for (const q of quotes) {
      // Escape backticks for template-literal safety.
      const clean = q.quote.replace(/`/g, "'");
      const src   = q.source.replace(/`/g, "'");
      injectionBlockLines.push(`  - "${clean}" (${src})`);
    }
    injectionBlockLines.push("");
  }

  const injectionBlock = injectionBlockLines.join("\n").trimEnd();

  const injectionExport = `export const INJECTED_QUOTES = \`${
    injectionBlock.replace(/\\/g, "\\\\").replace(/`/g, "\\`").replace(/\$\{/g, "\\${")
  }\`;
`;

  const output = header + injectionExport;
  fs.writeFileSync(OUTPUT_FILE, output, "utf8");

  // Stats to stdout.
  const totalQuotes = orderedMoves.reduce((sum, n) => sum + byMove[n].length, 0);
  const cappedInjected = orderedMoves.reduce(
    (sum, n) => sum + Math.min(byMove[n].length, MAX_QUOTES_PER_MOVE),
    0,
  );
  console.log(`✅ Synced ${totalQuotes} verbatim quotes across ${orderedMoves.length} moves.`);
  console.log(`   Injected ${cappedInjected} into engine prompt (cap ${MAX_QUOTES_PER_MOVE}/move).`);
  console.log(`   Wrote: ${OUTPUT_FILE}`);
  for (const n of orderedMoves) {
    const injected = Math.min(byMove[n].length, MAX_QUOTES_PER_MOVE);
    console.log(`   Move #${n} (${MOVE_NAMES[n]}): ${byMove[n].length} total, ${injected} injected`);
  }
}

// ─── main ─────────────────────────────────────────────────────────────
if (!fs.existsSync(RAW_QUOTES)) {
  console.error(`❌ Source file not found: ${RAW_QUOTES}`);
  process.exit(1);
}

const content = fs.readFileSync(RAW_QUOTES, "utf8");
const byMove  = parseQuotes(content);
emit(byMove);
